### Load data


::: {.cell}

```{.r .cell-code}
library(rlang)
library(cbbplotR)
options(chromote.headless = "new")

acc_bad <- readr::read_csv("acc-bad.csv") |> 
  dplyr::mutate(year = as.integer(stringr::str_sub(Season, 1, 4)) + 1) |> 
  dplyr::relocate(year) |> 
  dplyr::group_by(year) |> 
  dplyr::count(sort = TRUE) |> 
  dplyr::select(year, bad_teams = n)

acc_history <- readr::read_csv("acc-history.csv") |> 
  dplyr::select(year, total_teams, ncaa) |> 
  dplyr::add_row(year = 2025, total_teams = 18, ncaa = 3) |> 
  dplyr::left_join(acc_bad, by = "year") |> 
  dplyr::mutate(ncaa = dplyr::if_else(year == 2020, 5, ncaa),
                ncaa = dplyr::if_else(year == 2025, 4, ncaa)) |> 
  dplyr::mutate(
    ncaa_pct = ncaa/total_teams,
    bad_pct = bad_teams/total_teams
  ) |> 
  tidyr::replace_na(list(bad_teams = 0, bad_pct = 0)) |> 
  dplyr::arrange(-year)

# pbp data 

pbp <- readr::read_csv("pbp.csv")

cadeau_fouls <- pbp |>
  dplyr::filter(Player_1 == "ELLIOT.CADEAU" &
                  Event_Type == "Commits Foul") |>
  dplyr::mutate(
    opponent = dplyr::if_else(Home == "North Carolina", Away, Home),
    location = dplyr::if_else(Home == "North Carolina", "home", "at")
  ) |>
  dplyr::select(
    game_id = ID,
    opponent,
    location,
    half = Half_Status,
    game_time = Game_Time,
    game_seconds = Game_Seconds,
    player = Player_1,
    event = Event_Description,
  )
```
:::


### Custom theme


::: {.cell}

```{.r .cell-code}
theme_me <- function() {
  # Create a base theme with minimal style
  base_theme <- ggplot2::theme_minimal(base_size = 10, base_family = "RobotoCondensed-Regular")

  # Customize the base theme with additional modifications
  custom_theme <- base_theme +
    ggplot2::theme(
      plot.title = ggplot2::element_text(
        hjust = 0.5,
        size = 24,
        face = "bold"
      ),
      plot.subtitle = ggplot2::element_text(
        hjust = 0.5,
        size = 10,
        lineheight = 0.25,
        vjust = -0.5
      ),
      plot.caption = ggplot2::element_text(
        hjust = 1,
        size = 6,
        lineheight = 0.35,
        margin = ggplot2::margin(t = 20)
      ),
      plot.background = ggplot2::element_rect(fill = "floralwhite", color = "floralwhite")
    )

  return(custom_theme)
}
```
:::


