### Distro plot for fouls


::: {.cell}

```{.r .cell-code}
distro_plot <- cadeau_fouls |>
  dplyr::mutate(minute_bin = game_seconds %/% 300) |>
  dplyr::count(minute_bin) |>
  ggplot2::ggplot(ggplot2::aes(x = minute_bin * 5, y = n)) +
  ggplot2::geom_col(fill = "#56a0d3", color = "white") +
  hrbrthemes::theme_ipsum() +
  ggplot2::geom_text(
    ggplot2::aes(label = n),
    vjust = -0.5,
    size = 4,
    family = "Roboto Condensed",
    color = "gray20"
  ) +
  ggplot2::scale_x_continuous(
    breaks = seq(0, 45, by = 5),
    labels = c(
      "First 5 mins",
      "5-9 min",
      "10-15 min",
      "15-20 min",
      "20-25 min",
      "25-30 min",
      "30-35 min",
      "35-40 min",
      "Overtime",
      ""
    ) 
  ) +
  ggplot2::scale_y_continuous(limits = c(0, 20), breaks = seq(0, 20, 5)) +
  ggplot2::labs(
    title = "When is Elliot Cadeau whistled for fouls?",
    subtitle = "Shows total fouls committed in each five-minute segment of game time.  \nCadeau has committed a team-high 84 fouls this season.",
    x = "",
    y = "Foul Count",
    caption = "Data via bigballR through February 19, 2025 games  \nViz by Chris at Bless your Chart"
  ) +
  ggplot2::theme(
    plot.subtitle = ggtext::element_markdown(),
    plot.caption = ggtext::element_markdown(face = "plain"),
    panel.grid.major = ggplot2::element_blank()
  )

ggplot2::ggsave(
  "ec_plot.png",
  distro_plot,
  w = 8.5,
  h = 7.5,
  dpi = 600,
  type = 'cairo',
  bg = "white"
)

