### Fouls table


::: {.cell}

```{.r .cell-code}
ctbl <- cadeau_fouls |>
  dplyr::group_by(game_id, opponent) |>
  dplyr::arrange(game_seconds, .by_group = TRUE) |>
  dplyr::mutate(foul_number = dplyr::row_number()) |>
  dplyr::filter(foul_number <= 5) |>
  dplyr::select(game_id, opponent, foul_number, game_seconds) |>
  tidyr::pivot_wider(names_from = foul_number,
                     values_from = game_seconds,
                     names_prefix = "Foul_") |>
  dplyr::ungroup() |>
  dplyr::mutate(game_id = as.numeric(game_id)) |>
  dplyr::mutate(
    row_number = dplyr::case_match(
      game_id,
      5722933 ~ 1,
      5810067 ~ 2,
      5722945 ~ 3,
      5730381 ~ 4,
      5722959 ~ 5,
      5810062 ~ 6,
      5810055 ~ 7,
      5722389 ~ 8,
      5732549 ~ 9,
      5722995 ~ 10,
      5723013 ~ 11,
      5723033 ~ 12,
      5723044 ~ 13,
      5732557 ~ 14,
      5732566 ~ 15,
      5732572 ~ 16,
      5732517 ~ 17,
      5732590 ~ 18,
      5732592 ~ 19,
      5732601 ~ 20,
      5732390 ~ 21,
      5732607 ~ 22,
      5732612 ~ 23,
      5732616 ~ 24,
      5732625 ~ 25,
      5732624 ~ 26,
      5732578 ~ 27
    )
  ) |>
  dplyr::arrange(row_number) |>
  cbbplotR::gt_cbb_teams(opponent,
                         opponent,
                         include_name = TRUE,
                         logo_height = 20) |>
  gt::gt() |>
  gt::cols_hide(columns = c(row_number, game_id)) |>
  gt::fmt_markdown(opponent) |>
  gt::cols_label(
    opponent = "",
    Foul_1 = "1",
    Foul_2 = "2",
    Foul_3 = "3",
    Foul_4 = "4",
    Foul_5 = "5"
  ) |>
  gt::tab_spanner(columns = starts_with("Foul_"), label = "Time of game when each foul was committed") |>
  gt::fmt_missing(columns = gt::everything(), missing_text = "-") |>
  gt::fmt(
    columns = dplyr::starts_with("Foul_"),
    fns = function(x)
      ifelse(is.na(x), "-", sprintf("%d:%02d", x %/% 60, x %% 60))
  ) |>
  gt::tab_header(
    title = "When is Elliot Cadeau whistled for fouls?",
    subtitle = gt::md(
      "Shows timestamps of game time when Cadeau is charged with a foul.  \nHighlights any fouls committed in the first five minutes."
    )
  ) |>
  gt::tab_source_note(
    source_note = gt::html(
      "Shows timestamp of game, counting up to 40+ minutes, when the foul was committed. <br>Data through February 19, 2025 games<br><b>Table by Chris at Bless your chart | data via bigballR + stats.ncaa.org</b>"
    )
  ) |>
  gt::cols_align(align = "left") |>
  gtExtras::gt_theme_dot_matrix() |>
  gt::tab_options (
    source_notes.font.size = gt::px(10),
    row.striping.background_color = '#EEEEEE',
    table.font.size = gt::px(10),
    column_labels.text_transform = 'uppercase',
  ) |>
  gt::tab_style(
    style = list(gt::cell_fill(color = "#FFC1C3")),
    locations = gt::cells_body(
      columns = c("Foul_1"),
      rows = c(4, 5, 7, 11, 16, 18, 20, 22, 27)
    )
  ) |>
  gt::tab_style(
    style = list(gt::cell_fill(color = "#FFC1C3")),
    locations = gt::cells_body(columns = c("Foul_2"), rows = c(4, 7, 16))
  )  |>
  gtUtils::gt_border_grid(color = "black",
                          weight = 0.5,
                          include_labels = FALSE) |>
  gt::tab_style(
    locations = gt::cells_column_spanners(),
    style = gt::cell_text(transform = "capitalize")
  )  |>
  gtUtils::gt_border_bars_bottom(c("#56a0d3", "#89BDE0", "#BBD9ED"))


gtUtils::gt_save_crop(ctbl,
                      file = "c_tbl.png",
                      whitespace = 40,
                      bg = "white")

